$repo = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$prNum = 57
$timeout = 600
$interval = 30
$elapsed = 0
$findings = $null

while ($elapsed -lt $timeout) {
    # Strategy A: "Copilot's findings"
    $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.body | test("Copilot.s findings")) | .id' 2>$null
    if ($reviews) { $findings = "review"; break }

    # Strategy B: "Pull request overview"
    $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.body | test("Pull request overview")) | .id' 2>$null
    if ($reviews) { $findings = "review"; break }

    # Strategy C: copilot-pull-request-reviewer bot
    $reviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | .id' 2>$null
    if ($reviews) { $findings = "review"; break }

    # Strategy D: Line-level comments from "Copilot"
    $comments = gh api "/repos/$repo/pulls/$prNum/comments" --jq '.[] | select(.user.login == "Copilot") | .id' 2>$null
    if ($comments) { $findings = "comments"; break }

    Start-Sleep -Seconds $interval
    $elapsed += $interval
    Write-Host "Polling... elapsed=${elapsed}s"
}

if ($findings) {
    Write-Host "Copilot review detected via: $findings"
} else {
    Write-Host "TIMEOUT: No Copilot review found after ${timeout}s"
}

