$repo = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$prNum = 57
$timeout = 600
$interval = 30
$elapsed = 0
# We already know there's one review from before. We need to detect a NEW one.
$existingReviewIds = @("4739392419")

while ($elapsed -lt $timeout) {
    $allReviews = gh api "/repos/$repo/pulls/$prNum/reviews" --jq '.[] | select(.user.login | test("copilot-pull-request-reviewer")) | .id' 2>$null
    if ($allReviews) {
        $reviewList = $allReviews -split "`n" | Where-Object { $_ -and $_ -notin $existingReviewIds }
        if ($reviewList) {
            Write-Host "New Copilot review detected: $($reviewList -join ', ')"
            break
        }
    }
    Start-Sleep -Seconds $interval
    $elapsed += $interval
    Write-Host "Polling for new review... elapsed=${elapsed}s"
}

if ($elapsed -ge $timeout) {
    Write-Host "TIMEOUT: No new Copilot review found after ${timeout}s"
}

